## 6. GraphQL Controller 스켈레톤

파일 위치: `graphql/src/main/kotlin/com/maum/backend/controller/profile/ProfileController.kt`

```kotlin
@Controller
class ProfileController(
    private val profileService: ProfileService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun myProfile(
        @UserId userId: String,
    ): UserProfileResponse {
        val response = profileService.getProfile(userId, userId)
        return response.profile.toResponse()
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun userProfile(
        @UserId userId: String,
        @Argument userId: String,  // target
    ): UserProfileResponse? {
        return try {
            val response = profileService.getProfile(userId, userId)
            response.profile.toResponse()
        } catch (e: CustomGraphQLException) {
            if (e.errorCode == "NOT_FOUND") null else throw e
        }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfile(
        @UserId userId: String,
        @Argument input: UpdateProfileInput,
    ): UpdateProfilePayload {
        val response = profileService.updateProfile(userId, input)
        return UpdateProfilePayload(
            profile = response.profile.toResponse(),
            errors = emptyList(),
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateProfileImage(
        @UserId userId: String,
        @Argument input: UpdateProfileImageInput,
    ): UpdateProfilePayload {
        val response = profileService.updateProfileImage(userId, input)
        return UpdateProfilePayload(
            profile = response.profile.toResponse(),
            errors = emptyList(),
        )
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun updateVoiceIntro(
        @UserId userId: String,
        @Argument input: UpdateVoiceIntroInput,
    ): UpdateProfilePayload {
        val response = profileService.updateVoiceIntro(userId, input)
        return UpdateProfilePayload(
            profile = response.profile.toResponse(),
            errors = emptyList(),
        )
    }
}
